BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?ownerName ?nsName ?qname WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name "APS%20Maintainability" .
  ?req vocab:Element_owner ?owner .
  ?owner vocab:NamedElement_name ?ownerName .
  OPTIONAL { ?req vocab:NamedElement_namespace ?ns . ?ns vocab:NamedElement_name ?nsName . }
  OPTIONAL { ?req vocab:NamedElement_qualifiedName ?qname . }
}
LIMIT 5

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?name ?type WHERE {
  VALUES ?child {
    <TMT/hierarchyelement/TMT::Project::Work%20Packages::Project%20Systems%20Engineering::01%20Components::Operational::TMT%20Observatory%20System::Black%20Box%20Specification::TMT%20Requirements%20imported%20from%20DOORS::DRD%20APS::Introduction>
  }
  OPTIONAL { ?child vocab:NamedElement_name ?name . }
  OPTIONAL { ?child rdf:type ?type . }
}
LIMIT 5

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childName ?childType WHERE {
  ?child rdf:type ?childType .
  ?child vocab:NamedElement_name ?childName .
  FILTER(CONTAINS(STR(?child), "DRD%2520APS"))
  FILTER(NOT EXISTS {
    FILTER(CONTAINS(STR(?child), "DRD%2520APS::APS%2520Requirements::"))
  })
}
ORDER BY ?childName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?catName WHERE {
  {
    ?cat rdf:type vocab:package .
    ?cat vocab:NamedElement_name ?catName .
    FILTER(CONTAINS(STR(?cat), "03%2520APS%2520Requirements%2520individual%2520views"))
    FILTER(?catName != "03%20APS%20Requirements%20individual%20views")
  }
  UNION
  {
    ?cat vocab:NamedElement_name ?catName .
    FILTER(REGEX(STR(?cat), "DRD%2520APS::APS%2520Requirements::[^:]+$"))
    ?cat rdf:type ?t .
    FILTER(?t IN (vocab:hierarchyelement, vocab:tmt%20requirement))
  }
}
ORDER BY ?catName
